import{_ as t,H as n,f as a,i as o}from"./chunks/framework.BHvCMIhP.js";const c=JSON.parse('{"title":"八大谬误与故障模型","description":"","frontmatter":{},"headers":[],"relativePath":"distributedLearning/02-八大谬误与故障模型.md","filePath":"distributedLearning/02-八大谬误与故障模型.md","lastUpdated":1778496697000}'),r={name:"distributedLearning/02-八大谬误与故障模型.md"};function e(i,s,p,l,g,d){return n(),a("div",null,[...s[0]||(s[0]=[o(`<h1 id="八大谬误与故障模型" tabindex="-1">八大谬误与故障模型 <a class="header-anchor" href="#八大谬误与故障模型" aria-label="Permalink to &quot;八大谬误与故障模型&quot;">​</a></h1><p>1994 年,Sun 公司的 Peter Deutsch 列了一份「分布式计算八大谬误」(Fallacies of Distributed Computing),写到墙上贴给工程师看。<strong>30 年过去了,这份单子上的每一条都还在每年制造真实事故</strong>——AWS S3 大宕机、GitHub 24 小时数据库切换、Cloudflare BGP 黑洞,根上都是某条谬误被忽略。这一篇先把八大谬误配上真实事故讲完,然后引出更深一层的「<strong>故障模型</strong>」和「<strong>时间模型</strong>」——这两组词汇是后面 09 篇 FLP 不可能定理、14 篇 ZAB / EPaxos、15 篇拜占庭容错的前置弹药,<strong>搞不清楚故障模型,你看 Raft 论文都是云里雾里</strong>。</p><blockquote><p>一句话先记住:<strong>八大谬误总结起来就是一句&quot;网络不会按你期望工作&quot;</strong>——网络会丢包、会延迟、会断开、会被攻击、会被运维改坏。<strong>故障模型回答的是&quot;节点会以什么方式坏&quot;</strong>——崩了就死(Crash-stop)、崩了又活过来(Crash-recovery)、收到消息不回(Omission)、还是直接撒谎(Byzantine)。<strong>时间模型回答的是&quot;消息和处理有没有时间上限&quot;</strong>——同步(有上限)、异步(没上限)、部分同步(大部分时间有但偶尔没有)。<strong>FLP 告诉你纯异步系统连共识都不可能</strong>——所以工程上都假设&quot;部分同步&quot;。</p></blockquote><hr><h2 id="一、peter-deutsch-八大谬误" tabindex="-1">一、Peter Deutsch 八大谬误 <a class="header-anchor" href="#一、peter-deutsch-八大谬误" aria-label="Permalink to &quot;一、Peter Deutsch 八大谬误&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. The network is reliable             网络是可靠的</span></span>
<span class="line"><span>2. Latency is zero                     延迟为零</span></span>
<span class="line"><span>3. Bandwidth is infinite               带宽是无限的</span></span>
<span class="line"><span>4. The network is secure               网络是安全的</span></span>
<span class="line"><span>5. Topology doesn&#39;t change             拓扑结构不会变</span></span>
<span class="line"><span>6. There is one administrator          只有一个管理员</span></span>
<span class="line"><span>7. Transport cost is zero              传输成本为零</span></span>
<span class="line"><span>8. The network is homogeneous          网络是同构的</span></span></code></pre></div><p><strong>这八条都是&quot;反向的&quot;——意思是&quot;如果你假设这些为真,你就会出事&quot;</strong>。每一条都对应一类真实事故。下面一条一条拆开,配真实 post-mortem 看。</p><h3 id="_1-1-谬误一-网络是可靠的" tabindex="-1">1.1 谬误一:网络是可靠的 <a class="header-anchor" href="#_1-1-谬误一-网络是可靠的" aria-label="Permalink to &quot;1.1 谬误一:网络是可靠的&quot;">​</a></h3><p><strong>真相</strong>:网络会<strong>丢包、断开、抖动</strong>——AWS / Azure / Google Cloud 每天都有几次&quot;网络异常&quot;,<strong>生产系统必须假设网络永远会断</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>TCP 给你字节流可靠</span></span>
<span class="line"><span>   ↓ 但</span></span>
<span class="line"><span>TCP 之下是 IP,IP 会丢包</span></span>
<span class="line"><span>   ↓ 而且</span></span>
<span class="line"><span>TCP 重传会让&quot;慢&quot; → &quot;超时&quot; → &quot;连接断&quot;</span></span>
<span class="line"><span>   ↓ 业务层看到的是</span></span>
<span class="line"><span>&quot;对方挂了&quot; or &quot;网络断了&quot;——你区分不出</span></span></code></pre></div><p><strong>真实事故 1</strong>:<strong>2017 年 AWS S3 us-east-1 大宕机</strong>(2 月 28 日)。运维输入命令打错一个参数,<strong>把比预期多得多的服务器从子系统中下线</strong>。S3 索引子系统大半节点离线,<strong>整个 us-east-1 区域的 S3 不可用 4 小时</strong>——而很多依赖 S3 的服务(Slack、Trello、Quora)也跟着挂。<strong>根因不是网络物理故障,而是&quot;网络配置错误&quot;导致节点被切断</strong>——但表现和&quot;网络断了&quot;完全一样。</p><p><strong>真实事故 2</strong>:<strong>2019 年 Cloudflare BGP 路由抖动</strong>。某个边缘节点 BGP 配置错误,把全球流量的一部分错误地宣告到一个节点上,<strong>该节点过载而其他节点空闲</strong>——大量请求超时。整个 Cloudflare 全球网络出现 27 分钟异常。</p><p><strong>工程对策</strong>:</p><ul><li><strong>超时 + 重试</strong>(但要小心<strong>重试风暴</strong>——所有客户端同时重试压垮服务端,详见 systemDesign 限流篇)</li><li><strong>幂等设计</strong>——重试的请求不会副作用执行两次</li><li><strong>熔断降级</strong>——上游异常时主动放弃,不要把级联失败传播下去</li><li><strong>多可用区部署</strong>——单 AZ 网络故障不影响业务</li></ul><h3 id="_1-2-谬误二-延迟为零" tabindex="-1">1.2 谬误二:延迟为零 <a class="header-anchor" href="#_1-2-谬误二-延迟为零" aria-label="Permalink to &quot;1.2 谬误二:延迟为零&quot;">​</a></h3><p><strong>真相</strong>:<strong>任何网络调用都有不可忽视的延迟</strong>——同机房 ~500 μs,跨机房 ~10 ms,跨地域 ~100 ms,这是物理常数。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>单机内存访问 ~100 ns</span></span>
<span class="line"><span>RPC 同机房   ~500 μs   (5000 倍)</span></span>
<span class="line"><span>RPC 跨机房   ~10 ms    (10 万倍)</span></span>
<span class="line"><span>RPC 跨地域   ~100 ms   (100 万倍)</span></span></code></pre></div><p><strong>典型反模式</strong>:<strong>N+1 查询</strong>——本来一次能批量取的数据,改成循环 N 次调用,<strong>单机看不出问题,分布式直接超时</strong>:</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 反例:N 次 RPC</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> user_id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">in</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> user_ids:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    user </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> rpc_call(get_user, user_id)   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 100 个用户 → 100 次 RPC</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 正例:1 次批量</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">users </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> rpc_call(get_users_batch, user_ids)</span></span></code></pre></div><p><strong>真实事故</strong>:<strong>2016 年某电商促销</strong>——单接口本来 50 ms,促销当天链路上下游各加一次跨机房调用,<strong>链路从 1 次跨机房变 3 次,总延迟从 100 ms 涨到 300 ms</strong>,前端超时阈值 200 ms,<strong>整条链路雪崩</strong>。</p><p><strong>工程对策</strong>:</p><ul><li><strong>批量化</strong>:N 次调用合并成 1 次</li><li><strong>本地缓存</strong>:把&quot;频繁但低频变化&quot;的数据缓存在本地</li><li><strong>异步化</strong>:不阻塞主链路的逻辑改异步</li><li><strong>降级</strong>:超时时返回兜底数据,不无限重试</li></ul><h3 id="_1-3-谬误三-带宽是无限的" tabindex="-1">1.3 谬误三:带宽是无限的 <a class="header-anchor" href="#_1-3-谬误三-带宽是无限的" aria-label="Permalink to &quot;1.3 谬误三:带宽是无限的&quot;">​</a></h3><p><strong>真相</strong>:<strong>带宽永远有限</strong>,而且<strong>单机网卡上限 ~25 Gbps(普通) / ~400 Gbps(高端)</strong>,跨机房专线带宽更贵。</p><p><strong>典型反模式</strong>:<strong>循环传大数据</strong>——同事写一个微服务,<strong>把整张 1 GB 的用户表 RPC 传过来,本地过滤</strong>。单机看不出来,联调时网卡打满,把同机其他服务也拖死。</p><p><strong>真实事故</strong>:<strong>2018 年某直播平台</strong>——某条数据被错误地序列化成 50 MB(本应该 50 KB),每秒推送 1 万次 → <strong>500 GB/s 带宽需求,机房交换机直接饱和</strong>,所有服务都断网。<strong>根因:序列化 bug</strong>,但通过&quot;带宽假设无限&quot;的网络架构放大成全机房故障。</p><p><strong>工程对策</strong>:</p><ul><li><strong>数据压缩</strong>:gzip / snappy / zstd(尤其是日志和大对象)</li><li><strong>协议优化</strong>:Protobuf / Thrift / FlatBuffers 比 JSON 小 5-10 倍</li><li><strong>流式处理</strong>:大数据用流式 API,不一次 dump</li><li><strong>流量整形</strong>:对单连接设流量上限,防止单租户打爆</li></ul><h3 id="_1-4-谬误四-网络是安全的" tabindex="-1">1.4 谬误四:网络是安全的 <a class="header-anchor" href="#_1-4-谬误四-网络是安全的" aria-label="Permalink to &quot;1.4 谬误四:网络是安全的&quot;">​</a></h3><p><strong>真相</strong>:<strong>任何网络都可能被攻击</strong>——内网不是 VPN,VPN 不等于零信任,<strong>默认所有网络都不可信</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>传统模型:               零信任模型:</span></span>
<span class="line"><span>  内网 = 可信               每个请求都验证</span></span>
<span class="line"><span>  外网 = 不可信             不区分内外网</span></span>
<span class="line"><span>  防火墙隔开               服务间 mTLS</span></span></code></pre></div><p><strong>真实事故 1</strong>:<strong>2016 年 Mirai 僵尸网络</strong>——黑客通过默认密码的 IoT 设备组建 100 万节点僵尸网络,<strong>对 Dyn(DNS 服务)发起 DDoS,导致 Twitter、Spotify、Netflix 等大半个美国互联网不可用</strong>。</p><p><strong>真实事故 2</strong>:<strong>2017 年 Equifax 数据泄漏</strong>——黑客利用 Apache Struts 漏洞渗透<strong>内网</strong>,<strong>因为内部服务之间没有认证</strong>,横向移动拿到 1.4 亿用户数据。</p><p><strong>工程对策</strong>:</p><ul><li><strong>零信任架构</strong>:服务间 mTLS,不依赖&quot;内网信任&quot;</li><li><strong>最小权限</strong>:每个服务只能访问它必须访问的资源</li><li><strong>审计日志</strong>:所有跨服务调用记录,出事能追溯</li><li><strong>密钥管理</strong>:Vault / KMS / Secrets Manager,<strong>不要把密钥写代码里</strong></li></ul><h3 id="_1-5-谬误五-拓扑结构不会变" tabindex="-1">1.5 谬误五:拓扑结构不会变 <a class="header-anchor" href="#_1-5-谬误五-拓扑结构不会变" aria-label="Permalink to &quot;1.5 谬误五:拓扑结构不会变&quot;">​</a></h3><p><strong>真相</strong>:<strong>节点会上下线、IP 会变、机房会切换、网段会调整</strong>——拓扑变化是常态,<strong>写死 IP 的系统迟早崩</strong>。</p><p><strong>典型反模式</strong>:配置文件里写死 <code>mysql.host=10.0.0.5</code>——某天运维换机器,IP 变了,<strong>应用启动找不到 MySQL,全挂</strong>。</p><p><strong>真实事故</strong>:<strong>2012 年 Knight Capital 4.5 亿美元损失</strong>——升级交易系统,<strong>8 台服务器中有 1 台没升级,跑着旧版本的死代码,被新版本配置激活</strong>,该服务器在 45 分钟内疯狂下单,<strong>直接造成公司破产</strong>。根因:<strong>部署时没考虑&quot;拓扑不一致&quot;的情况</strong>。</p><p><strong>工程对策</strong>:</p><ul><li><strong>服务发现</strong>:ZK / etcd / Consul / Nacos,<strong>配置中心动态推送</strong></li><li><strong>DNS / 负载均衡</strong>:用域名 + LB 替代写死 IP</li><li><strong>K8s Service</strong>:服务名解析到当前 Pod 集合</li><li><strong>健康检查</strong>:节点下线自动从路由表摘除</li></ul><h3 id="_1-6-谬误六-只有一个管理员" tabindex="-1">1.6 谬误六:只有一个管理员 <a class="header-anchor" href="#_1-6-谬误六-只有一个管理员" aria-label="Permalink to &quot;1.6 谬误六:只有一个管理员&quot;">​</a></h3><p><strong>真相</strong>:<strong>真实系统有 N 个团队、N 个运维</strong>——每个组件都有不同的人管,<strong>配置可能互相冲突</strong>。</p><p><strong>真实事故 1</strong>:<strong>2018 年 GitHub 24 小时降级</strong>(10 月 21 日)。运维做日常网络维护,<strong>美东和美西的 MySQL 主从断开 43 秒</strong>,等恢复时<strong>两边都自己提了升主操作</strong>,出现&quot;双主写入&quot;。GitHub 团队选择回滚到东岸数据,<strong>期间 24 小时业务降级</strong>——根因不是单一故障,而是<strong>多团队协作下的复杂故障路径</strong>。</p><p><strong>真实事故 2</strong>:<strong>2021 年 Facebook 6 小时大宕机</strong>。BGP 路由更新错误,<strong>导致 Facebook 全球网络从互联网消失</strong>;更尴尬的是<strong>内部 DNS 也用同样的网络,工程师 SSH 登录修复的渠道也断了</strong>,只能派人去机房物理操作。<strong>根因:多团队的依赖耦合 + 没有&quot;管理通道独立&quot;</strong>。</p><p><strong>工程对策</strong>:</p><ul><li><strong>配置统一收口</strong>:配置中心 + 评审机制</li><li><strong>变更审批 + 灰度</strong>:任何变更先小范围,再扩大</li><li><strong>变更回滚预案</strong>:每次变更都要有 rollback 脚本</li><li><strong>混沌演练</strong>:故意制造&quot;两个团队同时变更&quot;的场景</li></ul><h3 id="_1-7-谬误七-传输成本为零" tabindex="-1">1.7 谬误七:传输成本为零 <a class="header-anchor" href="#_1-7-谬误七-传输成本为零" aria-label="Permalink to &quot;1.7 谬误七:传输成本为零&quot;">​</a></h3><p><strong>真相</strong>:<strong>每次跨进程调用都有 CPU、内存、网卡的成本</strong>——序列化、反序列化、TLS 握手、连接维护,<strong>累加起来不便宜</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>一次 RPC 的开销:</span></span>
<span class="line"><span>  序列化:1-100 μs (取决于数据量)</span></span>
<span class="line"><span>  网络发送:RTT ~ 0.5 ms 起步</span></span>
<span class="line"><span>  反序列化:1-100 μs</span></span>
<span class="line"><span>  对象 GC:不定 (Java 大对象触发 Full GC 可达秒级)</span></span></code></pre></div><p><strong>典型反模式</strong>:<strong>微服务粒度太细</strong>——一个业务请求拆成 50 个微服务,每个微服务再调 5 个下游,<strong>链路总长度 250+ 次 RPC</strong>,P99 延迟和故障率指数级放大。</p><p><strong>真实事故</strong>:<strong>2019 年某电商大促降级方案失效</strong>——本来某接口直接查 DB,改造成&quot;先查缓存服务 → 缓存服务调 Redis → 失败查 DB 服务 → DB 服务读 MySQL&quot;,<strong>4 次跨进程调用</strong>。日常流量没问题,<strong>大促时每环节都增加 5 ms 延迟,P99 从 50 ms 涨到 800 ms 直接超时</strong>。</p><p><strong>工程对策</strong>:</p><ul><li><strong>合理的微服务粒度</strong>:<strong>一个业务请求理想链路 ≤ 5 跳</strong></li><li><strong>同进程优先</strong>:能在同进程做的逻辑别拆服务</li><li><strong>连接复用</strong>:HTTP/2、gRPC 多路复用,避免重连开销</li><li><strong>二进制协议</strong>:Protobuf / Thrift,比 JSON 序列化快几倍</li></ul><h3 id="_1-8-谬误八-网络是同构的" tabindex="-1">1.8 谬误八:网络是同构的 <a class="header-anchor" href="#_1-8-谬误八-网络是同构的" aria-label="Permalink to &quot;1.8 谬误八:网络是同构的&quot;">​</a></h3><p><strong>真相</strong>:<strong>真实网络由不同硬件、不同协议、不同 MTU 组成</strong>——客户端 4G、办公网千兆、机房万兆、跨地域专线,<strong>性能特征完全不同</strong>。</p><p><strong>典型反模式</strong>:开发用本机测,<strong>所有请求都是 localhost(&lt; 100 μs)</strong>,上生产<strong>跨机房一跳 10 ms</strong>,核心链路超时。</p><p><strong>真实事故</strong>:<strong>2017 年某 IM 应用海外推送失败</strong>——国内推送链路 100 ms 内完成,海外用户经跨地域专线 + 当地运营商,<strong>P99 延迟 5 秒</strong>,推送服务的硬编码超时 1 秒,<strong>所有海外推送全失败</strong>。</p><p><strong>工程对策</strong>:</p><ul><li><strong>配置可调超时</strong>:不同区域 / 不同链路设不同超时</li><li><strong>本地化部署</strong>:边缘节点、CDN、就近接入</li><li><strong>协议适配</strong>:弱网下用更耐丢包的协议(QUIC、HTTP/3)</li><li><strong>真实链路压测</strong>:不能只测同机房,<strong>必须测跨地域 + 弱网</strong></li></ul><hr><h2 id="二、八大谬误之上的-九大谬误" tabindex="-1">二、八大谬误之上的&quot;九大谬误&quot; <a class="header-anchor" href="#二、八大谬误之上的-九大谬误" aria-label="Permalink to &quot;二、八大谬误之上的&quot;九大谬误&quot;&quot;">​</a></h2><p>行业里有人加了一条&quot;第九谬误&quot;:<strong>Everything will be fine if I follow best practices</strong>——&quot;我按最佳实践做就不会出事&quot;。这是更隐蔽的谬误,因为它让人放松警惕。</p><blockquote><p>真相是:<strong>最佳实践只是降低事故概率,不消除事故</strong>——你的系统永远会以你想不到的方式出事。<strong>心态比知识更重要</strong>——假设&quot;我的系统一定会以某种方式坏&quot;,然后设计容错,<strong>而不是&quot;我设计得很好所以不会坏&quot;</strong>。</p></blockquote><p>这种心态是后续 30 篇所有内容的底色——CAP / FLP / Linearizability 这些&quot;不可能定理&quot;反复在提醒你:<strong>有些事就是不可能,工程上必须妥协</strong>。</p><hr><h2 id="三、故障模型-failure-models" tabindex="-1">三、故障模型(Failure Models) <a class="header-anchor" href="#三、故障模型-failure-models" aria-label="Permalink to &quot;三、故障模型(Failure Models)&quot;">​</a></h2><p>讲完八大谬误,我们换一个视角:<strong>节点会以什么方式坏</strong>?这就是故障模型——分布式算法的设计必须先假设一个故障模型,<strong>不同模型对应不同的算法和成本</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>故障模型(从弱到强):</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Crash-stop      节点崩了就死,不再回来</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>  Crash-recovery  节点崩了之后可能恢复(本地状态可能丢)</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>  Omission        节点会&quot;遗漏&quot;——收到消息不回 / 发的消息丢</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>  Byzantine       节点会&quot;撒谎&quot;——可以发任意错误消息,甚至有恶意</span></span></code></pre></div><p><strong>模型越强,算法越复杂、成本越高</strong>。<strong>95% 的分布式中间件假设 Crash-recovery</strong>,只有区块链和金融国防场景才假设 Byzantine。</p><h3 id="_3-1-crash-stop-崩溃即死" tabindex="-1">3.1 Crash-stop(崩溃即死) <a class="header-anchor" href="#_3-1-crash-stop-崩溃即死" aria-label="Permalink to &quot;3.1 Crash-stop(崩溃即死)&quot;">​</a></h3><p>最简单的故障模型——<strong>节点要么活,要么彻底死,死了不复活</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>节点 A 状态:</span></span>
<span class="line"><span>  正常 → 崩溃(永久离线)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>不会发生:崩溃 → 恢复</span></span></code></pre></div><p><strong>特点</strong>:<strong>好分析、好实现,但不真实</strong>——真实世界节点重启后还会回来。</p><p><strong>适用场景</strong>:<strong>理论研究的简化模型</strong>。FLP 不可能定理就是在 Crash-stop 假设下证明的——<strong>连最简单的故障模型都能让纯异步系统共识不可能</strong>。</p><h3 id="_3-2-crash-recovery-崩溃可恢复" tabindex="-1">3.2 Crash-recovery(崩溃可恢复) <a class="header-anchor" href="#_3-2-crash-recovery-崩溃可恢复" aria-label="Permalink to &quot;3.2 Crash-recovery(崩溃可恢复)&quot;">​</a></h3><p><strong>最常见的工程模型</strong>——节点可能崩,但还能起来。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>节点 A 状态:</span></span>
<span class="line"><span>  正常 → 崩溃 → 恢复(可能丢失部分内存状态)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>恢复时:</span></span>
<span class="line"><span>  从持久化日志 / 快照恢复</span></span>
<span class="line"><span>  重新加入集群</span></span>
<span class="line"><span>  追上 Leader 的最新日志</span></span></code></pre></div><p><strong>关键问题</strong>:<strong>恢复后的&quot;我&quot;是不是原来的&quot;我&quot;</strong>?——这个问题不简单:</p><ul><li><strong>持久化的状态可能不完整</strong>(crash 时正在写盘)</li><li><strong>网络上其他节点可能已经认为&quot;它死了&quot;</strong>,而它复活后还以为自己是 Leader → 脑裂(详见 30 篇)</li></ul><p><strong>典型例子</strong>:<strong>etcd / ZooKeeper / Kafka / 任何用 Raft / Paxos 的系统</strong>——都假设 Crash-recovery 模型,<strong>节点重启后从持久化日志恢复</strong>。</p><h3 id="_3-3-omission-遗漏故障" tabindex="-1">3.3 Omission(遗漏故障) <a class="header-anchor" href="#_3-3-omission-遗漏故障" aria-label="Permalink to &quot;3.3 Omission(遗漏故障)&quot;">​</a></h3><p><strong>节点不崩,但消息会丢</strong>——可能是接收方收到了不回,可能是发送方发不出去,也可能网络中间丢了。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>两种子类型:</span></span>
<span class="line"><span>  Send omission:消息发不出(本地网卡故障 / 队列满)</span></span>
<span class="line"><span>  Receive omission:消息收到了不处理(协议栈丢 / 应用 bug)</span></span></code></pre></div><p><strong>特点</strong>:<strong>比 Crash 模型难处理</strong>——你不知道对方是真挂了还是临时不回。</p><p><strong>典型场景</strong>:<strong>网络分区 + 节点活着</strong>——节点 A 和节点 B 都活着,但 A 和 B 之间通信不上,<strong>对 A 来说 B &quot;好像挂了&quot;,对 B 来说 A &quot;好像挂了&quot;</strong>——双方都可能选举自己当 Leader,造成脑裂。</p><p><strong>工程对策</strong>:<strong>Quorum + 租约</strong>——多数派同意 + 时间窗口防止双主(详见 27 篇选主与租约)。</p><h3 id="_3-4-byzantine-拜占庭故障" tabindex="-1">3.4 Byzantine(拜占庭故障) <a class="header-anchor" href="#_3-4-byzantine-拜占庭故障" aria-label="Permalink to &quot;3.4 Byzantine(拜占庭故障)&quot;">​</a></h3><p><strong>最强模型——节点可以撒谎</strong>——发送错误消息、伪造身份、串通其他节点、有恶意。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Crash-stop:节点只会&quot;不响应&quot;</span></span>
<span class="line"><span>Omission:节点可能&quot;丢消息&quot;</span></span>
<span class="line"><span>Byzantine:节点可能&quot;发错的消息&quot; / &quot;发不一致的消息给不同节点&quot;</span></span></code></pre></div><p><strong>得名于&quot;拜占庭将军问题&quot;</strong>——几个将军围攻一座城,通过信使商量进攻还是撤退,但<strong>有的将军是叛徒,会发不同的消息给不同的人</strong>。如何让忠诚的将军们达成一致行动?</p><p><strong>关键数学结论</strong>:<strong>容忍 f 个拜占庭节点,需要至少 3f+1 个节点</strong>(Lamport / Shostak / Pease 1982)。<strong>容忍 1 个拜占庭节点需要 4 个节点,容忍 2 个需要 7 个</strong>——比 Crash 模型(2f+1)代价大得多。</p><p><strong>典型场景</strong>:</p><ul><li><strong>区块链</strong>:Bitcoin / Ethereum / 联盟链——节点之间不信任,可能有恶意</li><li><strong>金融跨机构清算</strong>:不同银行之间互不信任</li><li><strong>军事 / 航天</strong>:容错要求极高,<strong>硬件位翻转、电路故障</strong>都被视为&quot;撒谎&quot;</li></ul><p><strong>典型协议</strong>:<strong>PBFT(Practical Byzantine Fault Tolerance)、Tendermint、HotStuff</strong>——详见 15 篇。</p><h3 id="_3-5-几种模型的工程映射" tabindex="-1">3.5 几种模型的工程映射 <a class="header-anchor" href="#_3-5-几种模型的工程映射" aria-label="Permalink to &quot;3.5 几种模型的工程映射&quot;">​</a></h3><table tabindex="0"><thead><tr><th>系统</th><th>故障模型</th><th>理由</th></tr></thead><tbody><tr><td>Kafka</td><td>Crash-recovery</td><td>内部节点是自己人,不假设恶意</td></tr><tr><td>etcd / ZooKeeper</td><td>Crash-recovery</td><td>Raft / ZAB 协议都假设非拜占庭</td></tr><tr><td>MySQL / PostgreSQL</td><td>Crash-recovery</td><td>单一集群内部信任</td></tr><tr><td>Redis Cluster</td><td>Crash-recovery</td><td>同上</td></tr><tr><td>Bitcoin / Ethereum</td><td>Byzantine</td><td>全球节点互不信任,必须容忍恶意</td></tr><tr><td>Tendermint / Hyperledger</td><td>Byzantine</td><td>联盟链场景,部分节点可能作恶</td></tr><tr><td>Spanner / TiDB</td><td>Crash-recovery</td><td>Google / PingCAP 内部信任</td></tr></tbody></table><blockquote><p><strong>看一个分布式系统的文档,先找它假设什么故障模型</strong>——这决定了它能给你什么保证。<strong>假设 Crash 模型的系统不能放到不信任环境</strong>(联盟链不能用 etcd 做共识)、<strong>假设 Byzantine 模型的系统延迟和吞吐都差几个量级</strong>(区块链 TPS 几百 vs Raft 几万)。</p></blockquote><hr><h2 id="四、时间模型-timing-models" tabindex="-1">四、时间模型(Timing Models) <a class="header-anchor" href="#四、时间模型-timing-models" aria-label="Permalink to &quot;四、时间模型(Timing Models)&quot;">​</a></h2><p>故障模型回答&quot;怎么坏&quot;,时间模型回答&quot;消息延迟和处理时间有没有上限&quot;。这一组词汇是 FLP 不可能定理(09 篇)的关键前置。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>时间模型(从强到弱):</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Synchronous           消息延迟和处理时间都有已知上限</span></span>
<span class="line"><span>      ↓</span></span>
<span class="line"><span>  Partial Synchronous   存在上限,但你不知道具体值 / 偶尔会破</span></span>
<span class="line"><span>      ↓</span></span>
<span class="line"><span>  Asynchronous          没有任何时间假设</span></span></code></pre></div><h3 id="_4-1-synchronous-同步系统" tabindex="-1">4.1 Synchronous(同步系统) <a class="header-anchor" href="#_4-1-synchronous-同步系统" aria-label="Permalink to &quot;4.1 Synchronous(同步系统)&quot;">​</a></h3><p><strong>有严格的时间上限</strong>——消息一定在时间 T 内送达,节点处理一定在时间 P 内完成。</p><p><strong>好处</strong>:<strong>可以用超时来&quot;准确判断&quot;节点是否挂了</strong>——超过 T+P 没回就是挂了,不是慢。</p><p><strong>坏处</strong>:<strong>真实世界不存在严格同步的分布式系统</strong>——网络永远可能抖动,你给的上限永远可能被打破。</p><p><strong>适用</strong>:<strong>专用网络环境</strong>——电信网络的硬实时控制、卫星通信、某些工业控制系统。</p><h3 id="_4-2-asynchronous-异步系统" tabindex="-1">4.2 Asynchronous(异步系统) <a class="header-anchor" href="#_4-2-asynchronous-异步系统" aria-label="Permalink to &quot;4.2 Asynchronous(异步系统)&quot;">​</a></h3><p><strong>没有时间上限</strong>——消息可以任意延迟,处理可以任意慢,<strong>你永远不能用超时判断&quot;对方挂了&quot;</strong>。</p><p><strong>好处</strong>:<strong>最贴近真实互联网网络</strong>——没有任何&quot;网络一定 X ms 内到&quot;的保证。</p><p><strong>坏处</strong>:<strong>FLP 定理证明,在纯异步系统 + 一个节点可能崩溃的前提下,共识不可能</strong>(09 篇详解)。</p><p><strong>适用</strong>:<strong>严格的理论分析模型</strong>——证明&quot;什么不可能&quot;,而不是工程实现。</p><h3 id="_4-3-partial-synchronous-部分同步" tabindex="-1">4.3 Partial Synchronous(部分同步) <a class="header-anchor" href="#_4-3-partial-synchronous-部分同步" aria-label="Permalink to &quot;4.3 Partial Synchronous(部分同步)&quot;">​</a></h3><p><strong>Dwork / Lynch / Stockmeyer 1988 年提出</strong>——<strong>存在时间上限 T,但你不知道具体值;或者只是&quot;大部分时候&quot;满足上限,偶尔会破</strong>。</p><p><strong>实际含义</strong>:<strong>网络通常正常,偶尔抖动</strong>——这就是真实互联网的样子。</p><p><strong>关键</strong>:<strong>几乎所有工程上能用的共识算法(Paxos / Raft / ZAB),都假设部分同步</strong>——理论上 FLP 说异步不可能,工程上靠&quot;偶尔抖动结束后系统能收敛&quot;绕过去。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>       共识可达条件:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Synchronous     → 共识总是可能 (但模型不真实)</span></span>
<span class="line"><span>  Asynchronous    → 共识不可能 (FLP)</span></span>
<span class="line"><span>  Partial Sync    → 共识&quot;最终&quot;可能 (Paxos / Raft 都靠这个)</span></span>
<span class="line"><span>                    抖动期间不可能 collapse 终止性</span></span>
<span class="line"><span>                    抖动结束后保证收敛</span></span></code></pre></div><h3 id="_4-4-时间模型-故障模型-一个分布式问题的完整规约" tabindex="-1">4.4 时间模型 + 故障模型 = 一个分布式问题的完整规约 <a class="header-anchor" href="#_4-4-时间模型-故障模型-一个分布式问题的完整规约" aria-label="Permalink to &quot;4.4 时间模型 + 故障模型 = 一个分布式问题的完整规约&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                    Crash-stop  Crash-recovery  Omission  Byzantine</span></span>
<span class="line"><span>Synchronous       │   简单      │   常见       │   可行   │  可行(开销大)</span></span>
<span class="line"><span>Partial Sync      │   FLP绕过   │ Paxos/Raft   │  可行    │  PBFT</span></span>
<span class="line"><span>Asynchronous      │   FLP 阻断  │   FLP 阻断   │  阻断    │  阻断</span></span></code></pre></div><p><strong>这张表告诉你</strong>:</p><ul><li><strong>共识协议(Paxos / Raft)的精确假设是&quot;Partial Synchronous + Crash-recovery&quot;</strong></li><li><strong>区块链协议(PBFT / Tendermint)的精确假设是&quot;Partial Synchronous + Byzantine&quot;</strong></li><li><strong>任何号称&quot;全异步 + 容错&quot;的方案,要么是营销话术,要么是限定了 FLP 不影响的子问题</strong>(比如最终一致性)</li></ul><hr><h2 id="五、几个真实系统的故障模型分析" tabindex="-1">五、几个真实系统的故障模型分析 <a class="header-anchor" href="#五、几个真实系统的故障模型分析" aria-label="Permalink to &quot;五、几个真实系统的故障模型分析&quot;">​</a></h2><table tabindex="0"><thead><tr><th>系统</th><th>故障模型</th><th>时间模型</th><th>共识算法</th><th>失效场景</th></tr></thead><tbody><tr><td>Kafka</td><td>Crash-recovery</td><td>Partial Sync</td><td>ISR + ZK/KRaft</td><td>分区时少数派 broker 不可用</td></tr><tr><td>etcd</td><td>Crash-recovery</td><td>Partial Sync</td><td>Raft, N=2f+1</td><td>多数派失联立刻不可用</td></tr><tr><td>ZooKeeper</td><td>Crash-recovery</td><td>Partial Sync</td><td>ZAB(Paxos 变体)</td><td>Leader 切换期间不可用几秒</td></tr><tr><td>Bitcoin</td><td>Byzantine + 匿名</td><td>Async / Partial</td><td>PoW(算力多数)</td><td>7 TPS,确认 ~60 分钟</td></tr><tr><td>Hyperledger</td><td>Byzantine + 已知身份</td><td>Partial Sync</td><td>PBFT / HotStuff, 3f+1</td><td>节点数有限,吞吐千级</td></tr></tbody></table><p><strong>关键参数</strong>(以 Kafka 为例):</p><ul><li><code>acks=all</code>:写需要所有 ISR 副本确认(强持久化但慢)</li><li><code>min.insync.replicas</code>:最少同步副本数(防止单副本写)</li><li><code>unclean.leader.election.enable=false</code>:不允许选举不在 ISR 的副本(选 CP),为 true 则选 AP</li></ul><hr><h2 id="六、故障检测的根本困难" tabindex="-1">六、故障检测的根本困难 <a class="header-anchor" href="#六、故障检测的根本困难" aria-label="Permalink to &quot;六、故障检测的根本困难&quot;">​</a></h2><p>讲完模型,有一个深层问题必须挑明:<strong>在异步 / 部分同步系统里,你&quot;永远&quot;无法 100% 确定一个节点是真的挂了还是只是慢了</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>节点 A 给节点 B 发请求,等了 10 秒没回:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  情况一:B 崩溃了</span></span>
<span class="line"><span>  情况二:B 还活着,但处理慢</span></span>
<span class="line"><span>  情况三:B 还活着,但 A 到 B 的网络断了</span></span>
<span class="line"><span>  情况四:B 还活着,B 的回复在路上(还没到 A)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  → A 无法区分这四种情况</span></span></code></pre></div><p>这就是**&quot;故障检测的不完美性&quot;**——任何故障检测器都有 false positive(误报)和 false negative(漏报)。</p><p><strong>Perfect Failure Detector (P)</strong>:不误报、不漏报——<strong>异步系统中不可实现</strong>。 <strong>Eventually Perfect (◇P)</strong>:<strong>最终</strong>不误报、不漏报(分区结束后收敛)——部分同步系统中可实现。<strong>几乎所有工程检测器都是 ◇P</strong>。</p><p><strong>工程妥协</strong>:多次心跳超时(降低 FP)、Phi-accrual 输出&quot;可信度&quot;而非 0/1、Quorum 防脑裂(多数派同意才算挂)。这就是为什么 26 / 27 / 30 篇要花那么多笔墨——<strong>&quot;如何在不完美的故障检测下安全做出破坏性决策&quot;</strong>,是分布式工程师每天面对的问题。</p><hr><h2 id="七、强观点-很多生产事故的根本原因" tabindex="-1">七、强观点:很多生产事故的根本原因 <a class="header-anchor" href="#七、强观点-很多生产事故的根本原因" aria-label="Permalink to &quot;七、强观点:很多生产事故的根本原因&quot;">​</a></h2><p><strong>95% 的&quot;诡异&quot;分布式 bug,都能映射到八大谬误的某一条 + 故障模型的某个边界条件</strong>:</p><table tabindex="0"><thead><tr><th>现象</th><th>根本原因</th><th>对应谬误 / 模型</th></tr></thead><tbody><tr><td>双主 / 脑裂</td><td>网络分区 + Quorum 配置错</td><td>谬误 1+5,Omission</td></tr><tr><td>数据丢失</td><td>异步复制 + 主挂</td><td>谬误 1,Crash-recovery</td></tr><tr><td>超时雪崩</td><td>重试风暴 + 链路变长</td><td>谬误 2+7</td></tr><tr><td>跨地域延迟</td><td>部署假设单地域</td><td>谬误 2+8</td></tr><tr><td>配置回滚后失败</td><td>多团队配置冲突</td><td>谬误 6</td></tr><tr><td>升级后部分机器不工作</td><td>部分节点未升级</td><td>谬误 5+6</td></tr><tr><td>内网被攻破横向移动</td><td>内网默认可信</td><td>谬误 4</td></tr><tr><td>跨机房序列化爆带宽</td><td>大对象循环传输</td><td>谬误 3</td></tr><tr><td>节点假死活体</td><td>心跳错过被认为挂</td><td>Crash-recovery + 异步检测</td></tr><tr><td>区块链转账被恶意覆盖</td><td>51% 攻击</td><td>Byzantine 模型</td></tr></tbody></table><blockquote><p>出事故时<strong>先回到这张表</strong>——查清楚是哪条谬误被你忽略了、哪个故障模型的边界被你低估了——比&quot;加重试&quot;、&quot;加监控&quot;这种治标方案有效得多。</p></blockquote><hr><h2 id="八、读完这一篇后该有的认知" tabindex="-1">八、读完这一篇后该有的认知 <a class="header-anchor" href="#八、读完这一篇后该有的认知" aria-label="Permalink to &quot;八、读完这一篇后该有的认知&quot;">​</a></h2><ol><li><strong>网络永远不可靠</strong>——八大谬误的核心,<strong>你的系统必须显式处理网络抖动、延迟、分区、安全问题</strong></li><li><strong>故障模型不是教科书概念,是协议的前置假设</strong>——读论文 / 文档时<strong>先确定它假设什么故障模型</strong>,才能判断它在你场景能不能用</li><li><strong>Crash-recovery 是工程主流,Byzantine 是金融区块链特例</strong>——选错模型,要么浪费成本(用 PBFT 做内部协调),要么暴露安全风险(用 Raft 做跨机构清算)</li><li><strong>时间模型决定了能不能做共识</strong>——FLP 告诉你纯异步不行,工程都假设部分同步</li><li><strong>不完美的故障检测是常态</strong>——所有&quot;挂了&quot;的判断都是概率,设计时必须假设有误判</li></ol><hr><h2 id="九、踩坑提醒" tabindex="-1">九、踩坑提醒 <a class="header-anchor" href="#九、踩坑提醒" aria-label="Permalink to &quot;九、踩坑提醒&quot;">​</a></h2><ol><li><strong>以为内网就安全</strong>——零信任时代,<strong>所有调用都要认证</strong>,无差别 mTLS</li><li><strong>以为 TCP 可靠网络就可靠</strong>——TCP 给字节流可靠,<strong>连接断了重连后业务可能不可靠</strong></li><li><strong>本地开发没考虑跨机房 / 跨地域延迟</strong>——开发本地都 &lt; 1 ms,上线发现跨机房 10 ms,链路超时雪崩</li><li><strong>重试不加退避</strong>——所有客户端同时重试 → 服务端被 DDoS,<strong>重试必须 exponential backoff + jitter</strong></li><li><strong>超时设得太长或太短</strong>——太长 → 雪崩,太短 → 误判,<strong>不同链路不同超时</strong></li><li><strong>故障判定靠&quot;一次心跳超时&quot;</strong>——P99 网络可能 100 ms,正常心跳间隔太短就误判,<strong>用多次连续超时 + Phi-accrual</strong></li><li><strong>以为 Quorum 写就一定安全</strong>——少数派副本可能是旧的,<strong>读也要 Quorum 才能保证看到最新</strong></li><li><strong>用 Crash 模型协议跑在 Byzantine 环境</strong>——内部联盟链用 Raft,<strong>单个节点作恶就能改账本</strong></li><li><strong>以为&quot;网络分区很罕见&quot;</strong>——AWS / Azure 每月都有,<strong>生产代码必须容忍分区</strong></li><li><strong>以为最佳实践就万事大吉</strong>——所有大公司都按最佳实践做,<strong>事故照样发生</strong>——心态比知识重要</li></ol><hr><p>下一篇:<code>03-一致性、共识、一致性模型.md</code>——这三个词被混用了几十年,<strong>绝大多数面试 / 文档 / 文章都说错</strong>。我们把它们彻底分开:<strong>Consistency(一致性)是数据状态的相同程度,Consensus(共识)是节点达成一致的算法,Consistency Model(一致性模型)是程序员看到的契约</strong>。<strong>&quot;Kafka 是强一致&quot;为什么错、为什么 Linearizability 和 Sequential Consistency 完全不同、为什么单机内存模型(x86 TSO)和分布式一致性模型是同一套理论</strong>——读完再去看 Raft / Spanner / Riak 的论文,术语就不会再迷糊。</p>`,146)])])}const u=t(r,[["render",e]]);export{c as __pageData,u as default};
